import React, { useState } from 'react';
import './WordCloud.css';

const leftQuestions = [
  { text: 'Tell me about this data', size: 'xl' },
  { text: 'What are the top trends?', size: 'lg' },
  { text: 'Who are the top performers?', size: 'md' },
  { text: 'Show me year-over-year growth', size: 'lg' },
  { text: "What's changed recently?", size: 'sm' },
  { text: 'Summarise the key insights', size: 'md' },
];

const rightQuestions = [
  { text: 'Where are the biggest opportunities?', size: 'lg' },
  { text: 'Show me the latest results', size: 'md' },
  { text: "What's driving performance?", size: 'xl' },
  { text: 'Break it down by category', size: 'sm' },
  { text: 'Compare this year vs last year', size: 'lg' },
  { text: 'What stands out in the data?', size: 'md' },
];

function ChipColumn({ questions, active, onSelect, align }) {
  return (
    <div className={`wc-column wc-column--${align}`}>
      {questions.map((q) => (
        <button
          key={q.text}
          className={`wc-chip wc-${q.size} ${active === q.text ? 'wc-active' : ''}`}
          onClick={() => onSelect(q)}
        >
          {q.text}
        </button>
      ))}
    </div>
  );
}

export default function WordCloud({ onSelect }) {
  const [active, setActive] = useState(null);

  const handleClick = (q) => {
    setActive(q.text);
    onSelect(q.text);
    setTimeout(() => setActive(null), 1500);
  };

  return (
    <>
      <ChipColumn questions={leftQuestions} active={active} onSelect={handleClick} align="left" />
      <ChipColumn questions={rightQuestions} active={active} onSelect={handleClick} align="right" />
    </>
  );
}
